import java.io.*;
import java.util.Scanner;

public class TryWithResourcesExample {
    public static void main(String[] args) {
        // OLD way (pre-Java 7) — manual resource management
        System.out.println("=== Old Way (finally) ===");
        BufferedReader reader = null;
        try {
            reader = new BufferedReader(new FileReader("example.txt"));
            String line = reader.readLine();
            System.out.println("Line: " + line);
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        } finally {
            try {
                if (reader != null) {
                    reader.close();  // Must close manually!
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        }

        // NEW way (Java 7+) — try-with-resources
        System.out.println("=== try-with-resources ===");
        try (BufferedReader reader2 = new BufferedReader(new FileReader("example.txt"))) {
            String line = reader2.readLine();
            System.out.println("Line: " + line);
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }
        // Resources automatically closed!

        // Multiple resources
        System.out.println("=== Multiple Resources ===");
        try (BufferedReader br = new BufferedReader(new FileReader("input.txt"));
             BufferedWriter bw = new BufferedWriter(new FileWriter("output.txt"))) {
            String line;
            while ((line = br.readLine()) != null) {
                bw.write(line);
                bw.newLine();
            }
            System.out.println("File copied successfully!");
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }
        // Both resources are closed automatically!

        // Custom AutoCloseable resource
        System.out.println("=== Custom Resource ===");
        try (CustomResource resource = new CustomResource()) {
            resource.doSomething();
            // resource.close() called automatically
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}

// Custom AutoCloseable implementation
class CustomResource implements AutoCloseable {
    private boolean isOpen = true;

    void doSomething() throws Exception {
        if (!isOpen) {
            throw new Exception("Resource is closed!");
        }
        System.out.println("Doing something with resource...");
    }

    @Override
    public void close() throws Exception {
        System.out.println("CustomResource is being closed!");
        isOpen = false;
    }
}

phase1.explanation:
try-with-resources automatically closes resources:

What it does:
• Automatically calls close() on resources
• No more finally blocks for cleanup
• Cleaner, safer code

Requirements:
• Resources must implement AutoCloseable (or Closeable)
• Declared in try parentheses
• Resources are closed in reverse order

Syntax:
try (ResourceType var = new ResourceType()) {
    // use resource
} catch (Exception e) {
    // handle exceptions
}

Multiple resources:
try (ResourceType1 r1 = new ResourceType1();
     ResourceType2 r2 = new ResourceType2()) {
    // use resources
}

Benefits over finally:
• Less boilerplate code
• No null checks needed
• No nested try-catch for close()
• Resources closed in correct order

AutoCloseable vs Closeable:
• Closeable (old): throws IOException
• AutoCloseable (new): throws Exception (more flexible)

Common AutoCloseable resources:
• Scanner
• BufferedReader / BufferedWriter
• FileReader / FileWriter
• InputStream / OutputStream
• JDBC Connection, Statement

